import React from 'react';

export function InfoBadge({ label, status }) {
  const color = status === 'active' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800';
  return (
    <div className={`p-2 rounded-md ${color}`}>
      <span className="font-bold">{label}</span>: {status}
    </div>
  );
}

export function ActionButton({ taskId, onTrigger }) {
  return (
    <button onClick={() => onTrigger({ action: 'approve', id: taskId })} className="px-4 py-2 bg-blue-500 text-white rounded">
      Approve Task
    </button>
  );
}
